class Solution {
public:
    vector<int> separateDigits(vector<int>& nums) {
        vector<int> answer;
        for (int num : nums) {
            string strNum = to_string(num);
            for (char c : strNum) {
                answer.push_back(c - '0');
            }
        }
        return answer;
    }
};
efficiency: HIGH
time complexity: O(n*m)
space complexity: O(n*m)
energy implications: LOW
explanation: The solution iterates over each number in the input array, converts it to a string, and then iterates over each character in the string, converting it back to an integer and adding it to the result array. This approach is efficient as it only requires a single pass through the input array and its elements.
